local function check_permissions()
    local token = ngx.req.get_headers()["Authorization"]
    if not token then
        ngx.status = 401
        ngx.say("Unauthorized")
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Simulate token validation and role extraction
    local user_role = validate_token(token)

    if user_role == "admin" or user_role == "user" then
        return true
    else
        ngx.status = 403
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end
end

local function validate_token(token)
    -- Simulated token validation logic
    if token == "valid_admin_token" or token == "valid_user_token" then
        return string.sub(token, 1, -6)  -- Extract role from token
    else
        return nil
    end
end

if ngx.var.uri ~= "/admin" and ngx.var.uri ~= "/api" then
    check_permissions()
end